 ('1', '1', 'en_us', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2016-03-26 15:55:38', '2016-03-26 16:57:54', '21e2edc3-517f-43e3-9abe-fc26abfa9244'),
 ('2', '2', 'en_us', 'Home', '<h1>We craft experiences for the web, helping brands speak human in a <em>digital world</em>.</h1>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Digital Mastermind', 'Enriching brands through handcrafted digital experiences', NULL, '2016-03-26 15:55:41', '2017-02-04 16:35:09', '5ca94c02-0aa7-41e0-a06f-4df444fb3b94'),
 ('3', '3', 'en_us', 'Using White Space: How Emptiness Can Give So Much to Design', '<p>Craft is the CMS that’s powering Localhost. It’s beautiful, powerful, flexible, and easy-to-use, and it’s made by Pixel &amp; Tonic. We can’t wait to dive in and see what it’s capable of!<br /></p>\n\n<p>This is even more captivating content, which you couldn’t see on the News index page because it was entered after a Page Break, and the News index template only likes to show the content on the first page.</p>\n\n\n\n\n\n\n\n<p>Craft: a nice alternative to Word, if you’re making a website.</p>', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2016-03-26 15:55:41', '2017-02-04 17:06:16', '887c8ca4-2547-4ade-8e37-b0dd6003b728'),
