 ('16', '23', '4', '1', 'en_us', '1', '', '{\"typeId\":null,\"authorId\":\"1\",\"title\":\"Research Triangle Park\",\"slug\":\"research-triangle-park\",\"postDate\":1459038010,\"expiryDate\":null,\"enabled\":1,\"parentId\":null,\"fields\":{\"19\":\"Research Triangle Park\",\"14\":[\"18\"],\"16\":\"<p>Redesign WCS.org using a new brand aesthetic and audience-focused structure to more effectively share mission and attract supporters.<\\/p>\",\"18\":\"<p>A modern digital platform that tells a unique organizational story and inspires audience engagement, leading to 17% growth in end-of-year giving.<\\/p>\",\"17\":\"<p>Use the flexibility of the Rails CMS we developed to for WCS\\u2019s zoo facility sites to create customized pages that speak to and catalyze individual audiences through a bold new visual language.<\\/p>\",\"15\":\"<p><strong>120 years in the making.<\\/strong>&nbsp;Since 1895, the Wildlife Conservation Society (WCS) has worked to protect the world\\u2019s wildlife and wild places. Our partnership with WCS was entering its second year &mdash; following our creation of the groundbreaking 96 Elephants campaign and our redesign of their five zoo facility sites &mdash; when we turned our attention to WCS.org. To help WCS project their status as world-class conservation organization, we had already introduced a bold new brand approach to photography and design. The reimaging of WCS.org was the perfect opportunity to use this new aesthetic to showcase WCS\\u2019s global mission.<\\/p>\",\"2\":\"\"}}', '2016-03-27 00:20:10', '2016-03-27 00:20:10', 'a980536f-a3b0-47e2-94af-567a9624d33f'),
 ('17', '2', '1', '1', 'en_us', '5', '', '{\"typeId\":null,\"authorId\":null,\"title\":\"Home\",\"slug\":\"homepage\",\"postDate\":1459007741,\"expiryDate\":null,\"enabled\":1,\"parentId\":null,\"fields\":{\"1\":\"<p>It\\u2019s true, this site doesn\\u2019t have a whole lot of content yet, but don\\u2019t worry. Our web developers have just installed the CMS, and they\\u2019re setting things up for the content editors this very moment. Soon Localhost will be an oasis of fresh perspectives, sharp analyses, and astute opinions that will keep you coming back again and again.<\\/p><p>[button]Sample button[\\/button]<\\/p>\"}}', '2016-03-27 01:03:03', '2016-03-27 01:03:03', '0a13ff0c-fc58-472e-9fc7-fbddc07655b2'),
 ('18', '24', '6', '1', 'en_us', '1', NULL, '{\"typeId\":\"6\",\"authorId\":null,\"title\":\"Services\",\"slug\":\"services\",\"postDate\":1459041327,\"expiryDate\":null,\"enabled\":1,\"parentId\":null,\"fields\":[]}', '2016-03-27 01:15:27', '2016-03-27 01:15:27', 'db48171f-4e1e-4158-af00-ed1c4eae7f4c'),
 ('19', '24', '6', '1', 'en_us', '2', '', '{\"typeId\":null,\"authorId\":null,\"title\":\"Services\",\"slug\":\"services\",\"postDate\":1459041327,\"expiryDate\":null,\"enabled\":1,\"parentId\":null,\"fields\":{\"1\":\"<p>We are designers, engineers, and strategists. A team with a unique mix of skills knit together by our client-focused process, honed by decades of experience,&nbsp;that delivers&nbsp;real results, every time.<\\/p>\"}}', '2016-03-27 01:18:24', '2016-03-27 01:18:24', 'a59602c7-1cbd-42b9-b922-739813943edb'),
 ('20', '23', '4', '1', 'en_us', '2', '', '{\"typeId\":\"4\",\"authorId\":\"1\",\"title\":\"Elevating an eCommerce experience to the next level\",\"slug\":\"research-triangle-park\",\"postDate\":1459038000,\"expiryDate\":null,\"enabled\":1,\"parentId\":null,\"fields\":{\"19\":\"Research Triangle Park\",\"14\":[\"18\"],\"16\":\"<p>Redesign WCS.org using a new brand aesthetic and audience-focused structure to more effectively share mission and attract supporters.<\\/p>\",\"18\":\"<p>A modern digital platform that tells a unique organizational story and inspires audience engagement, leading to 17% growth in end-of-year giving.<\\/p>\",\"17\":\"<p>Use the flexibility of the Rails CMS we developed to for WCS\\u2019s zoo facility sites to create customized pages that speak to and catalyze individual audiences through a bold new visual language.<\\/p>\",\"15\":\"<p><strong>120 years in the making.<\\/strong>&nbsp;Since 1895, the Wildlife Conservation Society (WCS) has worked to protect the world\\u2019s wildlife and wild places. Our partnership with WCS was entering its second year &mdash; following our creation of the groundbreaking 96 Elephants campaign and our redesign of their five zoo facility sites &mdash; when we turned our attention to WCS.org. To help WCS project their status as world-class conservation organization, we had already introduced a bold new brand approach to photography and design. The reimaging of WCS.org was the perfect opportunity to use this new aesthetic to showcase WCS\\u2019s global mission.<\\/p>\",\"2\":\"\"}}', '2016-03-27 20:10:38', '2016-03-27 20:10:38', '8f6595c2-0b09-41f7-bb5b-83386dc31e5f'),
 ('21', '23', '4', '1', 'en_us', '3', '', '{\"typeId\":\"4\",\"authorId\":\"1\",\"title\":\"Elevating an eCommerce experience to the next level\",\"slug\":\"research-triangle-park\",\"postDate\":1459038000,\"expiryDate\":null,\"enabled\":1,\"parentId\":null,\"fields\":{\"19\":\"Research Triangle Park\",\"14\":[\"25\"],\"16\":\"<p>Redesign WCS.org using a new brand aesthetic and audience-focused structure to more effectively share mission and attract supporters.<\\/p>\",\"18\":\"<p>A modern digital platform that tells a unique organizational story and inspires audience engagement, leading to 17% growth in end-of-year giving.<\\/p>\",\"17\":\"<p>Use the flexibility of the Rails CMS we developed to for WCS\\u2019s zoo facility sites to create customized pages that speak to and catalyze individual audiences through a bold new visual language.<\\/p>\",\"15\":\"<p><strong>120 years in the making.<\\/strong>&nbsp;Since 1895, the Wildlife Conservation Society (WCS) has worked to protect the world\\u2019s wildlife and wild places. Our partnership with WCS was entering its second year &mdash; following our creation of the groundbreaking 96 Elephants campaign and our redesign of their five zoo facility sites &mdash; when we turned our attention to WCS.org. To help WCS project their status as world-class conservation organization, we had already introduced a bold new brand approach to photography and design. The reimaging of WCS.org was the perfect opportunity to use this new aesthetic to showcase WCS\\u2019s global mission.<\\/p>\",\"2\":\"\"}}', '2016-03-27 20:20:49', '2016-03-27 20:20:49', '80eb1551-a82f-436a-b8e1-763cfd4d5211'),
 ('22', '23', '4', '1', 'en_us', '4', '', '{\"typeId\":\"4\",\"authorId\":\"1\",\"title\":\"Elevating an eCommerce experience to the next level\",\"slug\":\"research-triangle-park\",\"postDate\":1459038000,\"expiryDate\":null,\"enabled\":1,\"parentId\":null,\"fields\":{\"19\":\"Research Triangle Park\",\"14\":[\"25\"],\"16\":\"<p>Redesign WCS.org using a new brand aesthetic and audience-focused structure to more effectively share mission and attract supporters.<\\/p>\",\"26\":{\"new1\":{\"type\":\"projectImage\",\"enabled\":\"1\",\"fields\":{\"projectImageSrc\":[\"30\",\"31\",\"32\"]}}},\"18\":\"<p>A modern digital platform that tells a unique organizational story and inspires audience engagement, leading to 17% growth in end-of-year giving.<\\/p>\",\"17\":\"<p>Use the flexibility of the Rails CMS we developed to for WCS\\u2019s zoo facility sites to create customized pages that speak to and catalyze individual audiences through a bold new visual language.<\\/p>\",\"15\":\"<p><strong>120 years in the making.<\\/strong>&nbsp;Since 1895, the Wildlife Conservation Society (WCS) has worked to protect the world\\u2019s wildlife and wild places. Our partnership with WCS was entering its second year &mdash; following our creation of the groundbreaking 96 Elephants campaign and our redesign of their five zoo facility sites &mdash; when we turned our attention to WCS.org. To help WCS project their status as world-class conservation organization, we had already introduced a bold new brand approach to photography and design. The reimaging of WCS.org was the perfect opportunity to use this new aesthetic to showcase WCS\\u2019s global mission.<\\/p>\",\"2\":\"\"}}', '2016-03-29 11:15:24', '2016-03-29 11:15:24', 'c9fcd9e7-9887-4e11-9ba1-cf69cf56b95e'),
