INSERT INTO `craft_entryversions` (`id`, `entryId`, `sectionId`, `creatorId`, `locale`, `num`, `notes`, `data`, `dateCreated`, `dateUpdated`, `uid`) VALUES
 ('107', '50', '4', '1', 'en_us', '10', '', '{\"typeId\":\"4\",\"authorId\":\"1\",\"title\":\"Sirchie\",\"slug\":\"sirchie\",\"postDate\":1459012380,\"expiryDate\":null,\"enabled\":0,\"parentId\":null,\"fields\":{\"19\":\"Sirchie\",\"14\":[\"88\"],\"34\":\"\",\"33\":\"Elevating an e-Commerce experience for crime scene investigators\",\"16\":\"<p>Connect with an audience DSG struggled to reach, and showcase women\\u2019s athletic clothing in a shippable and shareable format.<\\/p>\",\"26\":{\"86\":{\"type\":\"projectImage\",\"enabled\":\"1\",\"fields\":{\"projectImageSrc\":[\"85\",\"87\",\"90\"]}}},\"18\":\"<p>Users spent more than 6.3K total hours engaging with an interactive video lookbook that features custom photography, integrated share and shop features, and an empowering brand voice.<\\/p>\",\"17\":\"<p>Tell our audience\\u2019s story: Showcase the lives of women who personify both strength and femininity, and use athletic apparel as a key supporting character.<\\/p>\",\"15\":\"<p>Strong is the new skinny.&nbsp;This was the rallying cry behind the Women\\u2019s Fitness campaign we created for Dick\\u2019s Sporting Goods. DSG wanted to reach women who are serious about pushing their bodies, not to conform to society\\u2019s standards, but hit the goals they set for themselves. They want high-quality, on-trend, versatile clothing that meets both their athletic and aesthetic needs. We put DSG\\u2019s line of women\\u2019s apparel on their radar with a campaign that celebrates the lives of strong, beautiful women in a series of product-featuring storytelling vignettes.<\\/p>\",\"2\":[\"20\",\"21\",\"22\"]}}', '2017-01-15 21:55:38', '2017-01-15 21:55:38', '85d5a03b-5e1e-447e-8bea-5781f32ce2de'),
